import{_ as e,o,c as a,ag as n}from"./chunks/framework.DGzMGr_a.js";const g=JSON.parse('{"title":"MCP 和 Function Calling 怎么选","description":"","frontmatter":{"title":"MCP 和 Function Calling 怎么选","difficulty":"medium","tags":["MCP","function-calling","tool-use","protocol"],"estimate":15},"headers":[],"relativePath":"domains/ai/qa/qa-05-mcp-vs-function-calling.md","filePath":"domains/ai/qa/qa-05-mcp-vs-function-calling.md","lastUpdated":1783504823000}'),l={name:"domains/ai/qa/qa-05-mcp-vs-function-calling.md"};function r(s,t,i,c,d,p){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>构建 AI 应用时，既可以直接用 OpenAI / Anthropic 的 <strong>Function Calling</strong>，也可以接 <strong>Model Context Protocol（MCP）</strong>。请对比两者定位，并说明在前端 + BFF 架构里通常怎么落地。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>Function Calling（Tool Use）</strong></p><ul><li><strong>模型厂商 API 的一等功能</strong>：在 <code>chat.completions</code> 请求里带 <code>tools: [{ type: &#39;function&#39;, function: { name, parameters } }]</code>，模型返回 <code>tool_calls</code>。</li><li>执行逻辑在 <strong>你的服务端</strong>：收到 tool_calls 后自己调 DB、HTTP、脚本，再把结果以 <code>tool</code> 消息塞回。</li><li>优点：与模型深度集成、延迟低、无额外协议；缺点：<strong>每个应用自己对接 N 个后端</strong>，工具描述分散、难跨产品复用。</li></ul><p><strong>MCP（Model Context Protocol）</strong></p><ul><li><strong>开放协议</strong>（JSON-RPC），把「工具 + 资源 + 提示模板」封装成 <strong>MCP Server</strong>；<strong>MCP Client</strong>（如 Cursor、Claude Desktop、自建 Agent）统一连接。</li><li>Server 可独立进程、独立仓库、独立权限域；Client 发现 <code>tools/list</code>、<code>resources/read</code> 等标准能力。</li><li>优点：<strong>生态复用</strong>（接一个 GitHub MCP 处处可用）、权限边界清晰、适合 IDE 与多数据源；缺点：多一跳、部署运维更复杂，协议仍在演进。</li></ul><p><strong>怎么选（实用准则）</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>倾向</th></tr></thead><tbody><tr><td>单一 SaaS 内封闭工具集</td><td>Function Calling 直连即可</td></tr><tr><td>要接很多第三方数据源、团队共建工具</td><td>MCP Server</td></tr><tr><td>桌面 IDE / 开发者工具</td><td>MCP 已是事实标准之一</td></tr><tr><td>极致低延迟、无状态 chat</td><td>Function Calling 更简单</td></tr></tbody></table><p><strong>典型前端 + BFF 架构</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser (Chat UI)</span></span>
<span class="line"><span>    ↓ POST /api/chat (SSE)</span></span>
<span class="line"><span>BFF / Agent Runtime  ←→ LLM API (tools in request)</span></span>
<span class="line"><span>    ↓ execute</span></span>
<span class="line"><span>Internal APIs / MCP Client → MCP Server(s)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li><strong>浏览器不直连 MCP</strong>（安全：密钥、文件系统权限在服务端）；前端只展示 tool 状态与结果摘要。</li><li>BFF 充当 MCP Client：连接 <code>filesystem</code>、<code>github</code>、<code>lark</code> 等 server，把 <code>tools/list</code> 转成模型认识的 function schema。</li><li>同一应用可 <strong>混合</strong>：核心业务能力用内联 function，通用能力走 MCP。</li></ul><p><strong>与 Skills 的关系</strong>：MCP 提供「能做什么」；Skills 提供「这类任务怎么做」。二者互补。</p><h2 id="追问-1-mcp-的-resource-和-tool-对前端展示有何不同" tabindex="-1">追问 1：MCP 的 Resource 和 Tool 对前端展示有何不同？ <a class="header-anchor" href="#追问-1-mcp-的-resource-和-tool-对前端展示有何不同" aria-label="Permalink to &quot;追问 1：MCP 的 Resource 和 Tool 对前端展示有何不同？&quot;">​</a></h2><h3 id="答" tabindex="-1">答 <a class="header-anchor" href="#答" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li><strong>Tool</strong>：一次性动作，有输入输出，适合「搜索」「创建文档」按钮态展示（running / done / error）。</li><li><strong>Resource</strong>：可读实体（文件、文档 URI），适合「已附加上下文」侧栏，类似 <code>@file</code> 引用。</li><li>UI 上 resource 变更应触发上下文 token 估算更新；tool 结果则进入消息流折叠块。</li></ul><h2 id="追问-2-多个-mcp-server-工具名冲突怎么办" tabindex="-1">追问 2：多个 MCP Server 工具名冲突怎么办？ <a class="header-anchor" href="#追问-2-多个-mcp-server-工具名冲突怎么办" aria-label="Permalink to &quot;追问 2：多个 MCP Server 工具名冲突怎么办？&quot;">​</a></h2><h3 id="答-1" tabindex="-1">答 <a class="header-anchor" href="#答-1" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li>Client 层做 <strong>命名空间</strong>：<code>github__create_issue</code> vs <code>gitlab__create_issue</code>。</li><li>在转给模型前统一 prefix，执行时再 map 回真实 server + 原始名。</li><li>限制单轮暴露工具数量（Top-K 相关），避免 schema 过大占上下文。</li></ul><h2 id="追问-3-streamable-http-mcp-和-stdio-对部署有什么影响" tabindex="-1">追问 3：Streamable HTTP MCP 和 stdio 对部署有什么影响？ <a class="header-anchor" href="#追问-3-streamable-http-mcp-和-stdio-对部署有什么影响" aria-label="Permalink to &quot;追问 3：Streamable HTTP MCP 和 stdio 对部署有什么影响？&quot;">​</a></h2><h3 id="答-2" tabindex="-1">答 <a class="header-anchor" href="#答-2" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li><strong>stdio</strong>：本地子进程，适合桌面 IDE；难水平扩展，但简单。</li><li><strong>HTTP/SSE</strong>：远程服务，适合团队共享 MCP、K8s 部署；需处理鉴权、限流、超时。</li><li>前端无感，差异在 Agent 运行时；选 HTTP 时 BFF 要做连接池与健康检查。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/ai/RESOURCES">AI 应用 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://modelcontextprotocol.io/introduction" target="_blank" rel="noreferrer">Model Context Protocol (MCP)</a>：MCP 与单次 function calling 的定位差异与适用场景。</li><li><a href="https://platform.openai.com/docs/guides/function-calling" target="_blank" rel="noreferrer">OpenAI: Function calling</a>：厂商原生 tool schema，适合紧耦合 API。</li><li><a href="https://spec.modelcontextprotocol.io/specification/2024-11-05/basic/transports/" target="_blank" rel="noreferrer">MCP Specification: Transports</a>：stdio vs HTTP/SSE 传输层选型。</li></ul>`,25)])])}const h=e(l,[["render",r]]);export{g as __pageData,h as default};
